import json

def extract_names(obj):
    names = []
    if isinstance(obj, dict):
        for key, value in obj.items():
            if key == 'name':
                names.append(value)
            names.extend(extract_names(value))
    elif isinstance(obj, list):
        for item in obj:
            names.extend(extract_names(item))
    return names


def main():
    input_file = 'data.json'
    output_file = 'names.txt'

    try:
        with open(input_file, 'r', encoding='utf-8') as f:
            data = json.load(f)
    except json.JSONDecodeError as e:
        print(f'Error: Failed to parse JSON in {input_file}: {e}')
        return
    except FileNotFoundError:
        print(f'Error: File {input_file} not found.')
        return
    except OSError as e:
        print(f'Error: Could not read {input_file}: {e}')
        return

    names = extract_names(data)

    try:
        with open(output_file, 'w', encoding='utf-8') as f:
            for name in names:
                f.write(f"{name}\n")
    except OSError as e:
        print(f'Error: Could not write to {output_file}: {e}')
        return


if __name__ == '__main__':
    main()

